  `status` smallint DEFAULT '0' COMMENT 'С╝ўТЃатѕИуіХТђЂ№╝їтдѓТъюТў»0тѕЎТў»ТГБтИИтЈ»уће№╝ЏтдѓТъюТў»1тѕЎТў»У┐ЄТюЪ; тдѓТъюТў»2тѕЎТў»СИІТъХсђѓ',
