  `goods_value` varchar(1023) DEFAULT '[]' COMMENT 'тЋєтЊЂжЎљтѕХтђ╝№╝їgoods_typeтдѓТъюТў»0тѕЎуЕ║жЏєтљѕ№╝їтдѓТъюТў»1тѕЎТў»у▒╗уЏ«жЏєтљѕ№╝їтдѓТъюТў»2тѕЎТў»тЋєтЊЂжЏєтљѕсђѓ',
