  `time_type` smallint DEFAULT '0' COMMENT 'ТюЅТЋѕТЌХжЌ┤жЎљтѕХ№╝їтдѓТъюТў»0№╝їтѕЎтЪ║С║јжбєтЈќТЌХжЌ┤уџёТюЅТЋѕтцЕТЋ░days№╝ЏтдѓТъюТў»1№╝їтѕЎstart_timeтњїend_timeТў»С╝ўТЃатѕИТюЅТЋѕТюЪ№╝Џ',
  `days` smallint DEFAULT '0' COMMENT 'тЪ║С║јжбєтЈќТЌХжЌ┤уџёТюЅТЋѕтцЕТЋ░daysсђѓ',
