  `deleted` tinyint(1) DEFAULT '0' COMMENT 'жђ╗УЙЉтѕажЎц',
  PRIMARY KEY (`id`),
  KEY `code` (`code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='С╝ўТЃатѕИС┐АТЂ»тЈіУДётѕЎУАе';
