  `update_time` datetime DEFAULT NULL COMMENT 'ТЏ┤Тќ░ТЌХжЌ┤',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'жђ╗УЙЉтѕажЎц',
  PRIMARY KEY (`id`)
