DROP TABLE IF EXISTS `litemall_goods`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `litemall_goods` (
  `id` int NOT NULL AUTO_INCREMENT,
  `goods_sn` varchar(63) NOT NULL DEFAULT '' COMMENT 'тЋєтЊЂу╝ќтЈи',
  `name` varchar(127) NOT NULL DEFAULT '' COMMENT 'тЋєтЊЂтљЇуД░',
  `category_id` int DEFAULT '0' COMMENT 'тЋєтЊЂТЅђт▒ъу▒╗уЏ«ID',
  `brand_id` int DEFAULT '0',
  `gallery` varchar(1023) DEFAULT NULL COMMENT 'тЋєтЊЂт«БС╝атЏЙуЅЄтѕЌУАе№╝їжЄЄућеJSONТЋ░у╗ёТа╝т╝Ј',
  `season` varchar(20) DEFAULT NULL COMMENT '├Ц┬Г┬Б├е┼аРђџ├»┬╝┼Аspring/summer/autumn/winter/all_season',
  `style` varchar(50) DEFAULT NULL COMMENT '├Е┬Б┼й├д┬а┬╝├д┬аРђА├Д┬Г┬Й',
  `material` varchar(100) DEFAULT NULL COMMENT '├д┬Ю┬љ├е┬┤┬е',
  `size_table` text COMMENT '├Ц┬░┬║├Д┬а┬Ђ├е┬А┬еJSON',
  `keywords` varchar(255) DEFAULT '' COMMENT 'тЋєтЊЂтЁ│жћ«тГЌ№╝їжЄЄућежђЌтЈижЌ┤жџћ',
  `brief` varchar(255) DEFAULT '' COMMENT 'тЋєтЊЂу«ђС╗І',
  `is_on_sale` tinyint(1) DEFAULT '1' COMMENT 'Тў»тљдСИіТъХ',
  `status` varchar(20) DEFAULT 'draft' COMMENT 'уіХТђЂ№╝џdraft/pending/published',
  `sort_order` smallint DEFAULT '100',
  `pic_url` varchar(255) DEFAULT NULL COMMENT 'тЋєтЊЂжАхжЮбтЋєтЊЂтЏЙуЅЄ',
  `share_url` varchar(255) DEFAULT NULL COMMENT 'тЋєтЊЂтѕєС║ФТхиТіЦ',
  `is_new` tinyint(1) DEFAULT '0' COMMENT 'Тў»тљдТќ░тЊЂждќтЈЉ№╝їтдѓТъюУ«Йуй«тѕЎтЈ»С╗ЦтюеТќ░тЊЂждќтЈЉжАхжЮбт▒Ћуц║',
  `is_hot` tinyint(1) DEFAULT '0' COMMENT 'Тў»тљдС║║Т░ћТјеУЇљ№╝їтдѓТъюУ«Йуй«тѕЎтЈ»С╗ЦтюеС║║Т░ћТјеУЇљжАхжЮбт▒Ћуц║',
  `is_special_price` bit(1) DEFAULT b'0' COMMENT 'Тў»тљдуЅ╣С╗и',
  `special_price` decimal(10,2) DEFAULT NULL COMMENT 'уЅ╣С╗ижЄЉжбЮ',
  `is_presale` tinyint(1) DEFAULT '0' COMMENT 'Тў»тљджбётћ«№╝џ0-тљд№╝ї1-Тў»',
  `unit` varchar(31) DEFAULT 'РђЎС╗ХРђў' COMMENT 'тЋєтЊЂтЇЋСйЇ№╝їСЙІтдѓС╗ХсђЂуЏњ',
  `counter_price` decimal(10,2) DEFAULT '0.00' COMMENT 'СИЊТЪюС╗иТа╝',
  `retail_price` decimal(10,2) DEFAULT '100000.00' COMMENT 'жЏХтћ«С╗иТа╝',
  `detail` text COMMENT 'тЋєтЊЂУ»ду╗єС╗Іу╗Ї№╝їТў»т»їТќЄТюгТа╝т╝Ј',
  `add_time` datetime DEFAULT NULL COMMENT 'тѕЏт╗║ТЌХжЌ┤',
  `update_time` datetime DEFAULT NULL COMMENT 'ТЏ┤Тќ░ТЌХжЌ┤',
  `deleted` tinyint(1) DEFAULT '0' COMMENT 'жђ╗УЙЉтѕажЎц',
  `scene_tags` text COMMENT 'тю║ТЎ»ТаЄуГЙJSONТЋ░у╗ё№╝їтдѓ["ТЌЦтИИжђџтІц","у║дС╝џУЂџжцљ"]',
  `goods_params` text COMMENT 'тЋєтЊЂтЈѓТЋ░JSONТЋ░у╗ё№╝їтдѓ[{"key":"жЮбТќЎ","value":"ТБЅж║╗"}]',
  PRIMARY KEY (`id`),
  KEY `goods_sn` (`goods_sn`),
  KEY `cat_id` (`category_id`),
  KEY `brand_id` (`brand_id`),
  KEY `sort_order` (`sort_order`)
) ENGINE=InnoDB AUTO_INCREMENT=1181709 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='тЋєтЊЂтЪ║ТюгС┐АТЂ»УАе';
/*!40101 SET character_set_client = @saved_cs_client */;

