CREATE TABLE `litemall_order_goods` (
  `id` int NOT NULL AUTO_INCREMENT,
  `order_id` int NOT NULL DEFAULT '0' COMMENT 'У«бтЇЋУАеуџёУ«бтЇЋID',
  `goods_id` int NOT NULL DEFAULT '0' COMMENT 'тЋєтЊЂУАеуџётЋєтЊЂID',
  `goods_name` varchar(127) NOT NULL DEFAULT '' COMMENT 'тЋєтЊЂтљЇуД░',
  `goods_sn` varchar(63) NOT NULL DEFAULT '' COMMENT 'тЋєтЊЂу╝ќтЈи',
  `product_id` int NOT NULL DEFAULT '0' COMMENT 'тЋєтЊЂУ┤ДтЊЂУАеуџёУ┤ДтЊЂID',
  `sku_id` int DEFAULT NULL COMMENT 'SKU ID',
  `color` varchar(50) DEFAULT NULL COMMENT '├Е┬б┼Њ├еРђ░┬▓',
  `size` varchar(20) DEFAULT NULL COMMENT '├Ц┬░┬║├Д┬а┬Ђ',
  `number` smallint NOT NULL DEFAULT '0' COMMENT 'тЋєтЊЂУ┤ДтЊЂуџёУ┤ГС╣░ТЋ░жЄЈ',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'тЋєтЊЂУ┤ДтЊЂуџётћ«С╗и',
  `specifications` varchar(1023) NOT NULL COMMENT 'тЋєтЊЂУ┤ДтЊЂуџёУДёТа╝тѕЌУАе',
  `pic_url` varchar(255) NOT NULL DEFAULT '' COMMENT 'тЋєтЊЂУ┤ДтЊЂтЏЙуЅЄТѕќУђЁтЋєтЊЂтЏЙуЅЄ',
  `comment` int DEFAULT '0' COMMENT 'У«бтЇЋтЋєтЊЂУ»ёУ«║№╝їтдѓТъюТў»-1№╝їтѕЎУХЁТюЪСИЇУЃйУ»ёС╗и№╝ЏтдѓТъюТў»0№╝їтѕЎтЈ»С╗ЦУ»ёС╗и№╝ЏтдѓТъютЁХС╗ќтђ╝№╝їтѕЎТў»commentУАежЄїжЮбуџёУ»ёУ«║IDсђѓ',
  `add_time` datetime DEFAULT NULL COMMENT 'тѕЏт╗║ТЌХжЌ┤',
  `update_time` datetime DEFAULT NULL COMMENT 'ТЏ┤Тќ░ТЌХжЌ┤',
  `deleted` tinyint(1) DEFAULT '0' COMMENT 'жђ╗УЙЉтѕажЎц',
  PRIMARY KEY (`id`),
  KEY `order_id` (`order_id`),
  KEY `goods_id` (`goods_id`)
