CREATE TABLE `litemall_user` (
  `id` int NOT NULL AUTO_INCREMENT,
  `username` varchar(63) NOT NULL COMMENT 'ућеТѕитљЇуД░',
  `password` varchar(63) NOT NULL DEFAULT '' COMMENT 'ућеТѕит»єуаЂ',
  `gender` tinyint NOT NULL DEFAULT '0' COMMENT 'ТђДтѕФ№╝џ0 ТюфуЪЦ№╝ї 1ући№╝ї 1 тЦ│',
  `birthday` date DEFAULT NULL COMMENT 'ућЪТЌЦ',
  `last_login_time` datetime DEFAULT NULL COMMENT 'ТюђУ┐ЉСИђТгАуЎ╗тйЋТЌХжЌ┤',
  `last_login_ip` varchar(63) NOT NULL DEFAULT '' COMMENT 'ТюђУ┐ЉСИђТгАуЎ╗тйЋIPтю░тЮђ',
  `user_level` tinyint DEFAULT '0' COMMENT '0 ТЎ«жђџућеТѕи№╝ї1 VIPућеТѕи№╝ї2 жФўу║ДVIPућеТѕи',
  `nickname` varchar(63) NOT NULL DEFAULT '' COMMENT 'ућеТѕиТўхуД░ТѕќуйЉу╗ютљЇуД░',
