  `level_id` int DEFAULT NULL COMMENT '├ц┬╝┼А├ЦРђў╦ю├Д┬ГРђ░├Д┬║┬ДID',
  `total_points` int DEFAULT '0' COMMENT '├Д┬┤┬»├е┬«┬А├Д┬Д┬»├Ц╦єРђа',
  `available_points` int DEFAULT '0' COMMENT '├Ц┬Ј┬»├ДРђЮ┬е├Д┬Д┬»├Ц╦єРђа',
  `guide_id` int DEFAULT NULL COMMENT '├Д┬╗Рђў├Ц┬«┼А├Ц┬»┬╝├е┬┤┬ГID',
  `store_id` int DEFAULT NULL COMMENT '├Ц┬йРђЎ├Ц┬▒┼Й├ЕРђћ┬е├Ц┬║РђћID',
  `role` varchar(63) DEFAULT NULL,
  `role_ids` varchar(255) DEFAULT NULL COMMENT 'УДњУЅ▓IDтѕЌУАе(JSONТЋ░у╗ё)',
  `avatar` varchar(255) NOT NULL DEFAULT '' COMMENT 'ућеТѕитц┤тЃЈтЏЙуЅЄ',
  `weixin_openid` varchar(63) NOT NULL DEFAULT '' COMMENT 'тЙ«С┐АуЎ╗тйЋopenid',
  `session_key` varchar(100) NOT NULL DEFAULT '' COMMENT 'тЙ«С┐АуЎ╗тйЋС╝џУ»ЮKEY',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '0 тЈ»уће, 1 удЂуће, 2 Т│ежћђ',
  `add_time` datetime DEFAULT NULL COMMENT 'тѕЏт╗║ТЌХжЌ┤',
  `update_time` datetime DEFAULT NULL COMMENT 'ТЏ┤Тќ░ТЌХжЌ┤',
  `deleted` tinyint(1) DEFAULT '0' COMMENT 'жђ╗УЙЉтѕажЎц',
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_name` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=1041 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='ућеТѕиУАе';
